export const FloatingNav = ({
  navItems,
  className,
  onNavigate,
  activeSection,
}: {
  navItems: {
    name: string;
    link: string;
    icon?: React.ReactNode;
    id: string;
  }[];
  className?: string;
  onNavigate?: (id: string) => void;
  activeSection?: string;
}) => {
