      const previous = scrollYProgress.getPrevious();
      const direction = current - (previous ?? 0);

      if (current < 0.02) {
        // Always show at the very top
        setVisible(true);
      } else {
        if (direction < 0) {
          // Show when scrolling up
          setVisible(true);
        } else {
          // Hide when scrolling down
          setVisible(false);
        }
      }
    }
  });

  const handleLinkClick = (e: React.MouseEvent, id: string) => {
    e.preventDefault();
    if (onNavigate) {
      onNavigate(id);
    }
  };

