import React, { useRef, useState } from "react";
import { motion, useMotionValue, useSpring, useTransform, AnimatePresence } from "framer-motion";
import { ChevronLeft, ChevronRight, Instagram } from "lucide-react";

// Simulando os slides do post do Instagram mencionado
const POST_SLIDES = [
  {
    id: 1,
    url: "/hero-consultoria.png", // Imagem principal que você subiu
    fallback: "https://images.unsplash.com/photo-1616748494672-c0e663a04285?auto=format&fit=crop&q=80&w=800",
  },
  {
    id: 2,
    url: "/slide-2.png", 
    fallback: "https://images.unsplash.com/photo-1594882645126-14020914d58d?auto=format&fit=crop&q=80&w=800",
  },
  {
    id: 3,
    url: "/slide-3.png",
    fallback: "https://images.unsplash.com/photo-1517836357463-d25dfeac3438?auto=format&fit=crop&q=80&w=800",
  }
];

export const InteractiveHeroImage = () => {
  const [currentSlide, setCurrentSlide] = useState(0);
  const ref = useRef<HTMLDivElement>(null);

  const x = useMotionValue(0);
  const y = useMotionValue(0);

  const mouseXSpring = useSpring(x);
  const mouseYSpring = useSpring(y);

  const rotateX = useTransform(mouseYSpring, [-0.5, 0.5], ["15deg", "-15deg"]);
  const rotateY = useTransform(mouseXSpring, [-0.5, 0.5], ["-15deg", "15deg"]);

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!ref.current) return;
    const rect = ref.current.getBoundingClientRect();
    const width = rect.width;
    const height = rect.height;
    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;
    const xPct = mouseX / width - 0.5;
    const yPct = mouseY / height - 0.5;
    x.set(xPct);
    y.set(yPct);
  };

  const handleMouseLeave = () => {
    x.set(0);
    y.set(0);
  };

  const nextSlide = (e: React.MouseEvent) => {
    e.stopPropagation();
    setCurrentSlide((prev) => (prev + 1) % POST_SLIDES.length);
  };

  const prevSlide = (e: React.MouseEvent) => {
    e.stopPropagation();
    setCurrentSlide((prev) => (prev - 1 + POST_SLIDES.length) % POST_SLIDES.length);
  };

  return (
    <div className="relative w-full max-w-md mx-auto perspective-[1000px] group/container">
      {/* Background Glow */}
      <div className="absolute inset-0 bg-purple-600/30 blur-[120px] rounded-full animate-pulse" />

      <motion.div
        ref={ref}
        onMouseMove={handleMouseMove}
        onMouseLeave={handleMouseLeave}
        style={{
          rotateX,
          rotateY,
          transformStyle: "preserve-3d",
        }}
        animate={{
          y: [0, -15, 0],
        }}
        transition={{
          y: {
            duration: 4,
            repeat: Infinity,
            ease: "easeInOut",
          },
        }}
        className="relative z-10 w-full aspect-[4/5] rounded-[2.5rem] overflow-hidden border border-white/10 shadow-2xl bg-zinc-900 group cursor-default"
      >
        {/* Instagram Header Mockup */}
        <div className="absolute top-0 left-0 right-0 p-4 z-20 bg-gradient-to-b from-black/80 to-transparent flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 rounded-full border border-purple-500 p-0.5">
              <img src="/tiromero-perfil.jpg" className="w-full h-full rounded-full object-cover" onError={(e) => (e.target as HTMLImageElement).src = "https://images.unsplash.com/photo-1534438327276-14e5300c3a48?auto=format&fit=crop&q=80&w=100"} />
            </div>
            <span className="text-white text-xs font-black tracking-tight">tiromero</span>
          </div>
          <Instagram className="w-4 h-4 text-white/50" />
        </div>

        {/* Carousel Content */}
        <div className="relative w-full h-full">
          <AnimatePresence mode="wait">
            <motion.img
              key={currentSlide}
              src={POST_SLIDES[currentSlide].url}
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -20 }}
              transition={{ duration: 0.3 }}
              alt={`Slide ${currentSlide + 1}`}
              className="w-full h-full object-cover"
              onError={(e) => {
                (e.target as HTMLImageElement).src = POST_SLIDES[currentSlide].fallback;
              }}
            />
          </AnimatePresence>
        </div>

        {/* Navigation Arrows */}
        <div className="absolute inset-y-0 left-0 right-0 flex items-center justify-between px-4 z-30 opacity-0 group-hover:opacity-100 transition-opacity">
          <button 
            onClick={prevSlide}
            className="w-10 h-10 rounded-full bg-black/50 backdrop-blur-md border border-white/10 flex items-center justify-center text-white hover:bg-purple-600 transition-colors"
          >
            <ChevronLeft className="w-6 h-6" />
          </button>
          <button 
            onClick={nextSlide}
            className="w-10 h-10 rounded-full bg-black/50 backdrop-blur-md border border-white/10 flex items-center justify-center text-white hover:bg-purple-600 transition-colors"
          >
            <ChevronRight className="w-6 h-6" />
          </button>
        </div>

        {/* Pagination Dots */}
        <div className="absolute bottom-20 left-0 right-0 flex justify-center gap-1.5 z-30">
          {POST_SLIDES.map((_, i) => (
            <div 
              key={i} 
              className={`w-1.5 h-1.5 rounded-full transition-all duration-300 ${i === currentSlide ? 'bg-purple-500 w-4' : 'bg-white/30'}`} 
            />
          ))}
        </div>

        {/* Overlay para dar profundidade */}
        <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-transparent to-transparent opacity-60" />

        {/* Elementos flutuantes em 3D */}
        <motion.div 
          style={{ translateZ: "50px" }}
          className="absolute bottom-6 left-6 right-6 p-4 bg-white/5 backdrop-blur-md rounded-2xl border border-white/10 shadow-2xl"
        >
          <div className="flex items-center gap-3">
            <div className="w-8 h-8 bg-purple-600 rounded-lg flex items-center justify-center">
               <span className="text-[10px] font-black">TR</span>
            </div>
            <div>
              <p className="text-white font-black text-[10px] uppercase tracking-widest leading-none">Slide {currentSlide + 1} de {POST_SLIDES.length}</p>
              <p className="text-zinc-400 text-[9px] font-bold mt-1">Clique nas setas para ver mais</p>
            </div>
          </div>
        </motion.div>
      </motion.div>

      {/* Decoração Extra */}
      <div className="absolute -top-10 -right-10 w-24 h-24 bg-purple-500/20 rounded-full blur-2xl" />
      <div className="absolute -bottom-10 -left-10 w-32 h-32 bg-indigo-500/10 rounded-full blur-2xl" />
    </div>
  );
};

