import { Star, MessageSquare } from "lucide-react";

interface Feedback {
  name: string;
  text: string;
  tag: string;
  date?: string;
}

// URL do seu Google Apps Script (Exemplo: https://script.google.com/macros/s/.../exec)
// Se estiver vazio, ele usará os dados de demonstração.
const API_URL = ""; 

const DEMO_FEEDBACKS: Feedback[] = [
  { name: "Carlos Magno", text: "O protocolo de pernas mudou meu jogo. Em 3 semanas a definição já é outra!", tag: "Hipertrofia" },
  { name: "Mariana Costa", text: "Suporte nota 1000. O Tiromero responde rápido e corrige cada detalhe do movimento.", tag: "Consultoria" },
  { name: "Joaquim Neto", text: "Treinar com ciência é outra coisa. Menos tempo na academia e muito mais resultado.", tag: "Performance" },
];

export const LiveFeedbacks = () => {
  const [feedbacks, setFeedbacks] = useState<Feedback[]>(DEMO_FEEDBACKS);
  const [loading, setLoading] = useState(false);
  const [lastUpdate, setLastUpdate] = useState(new Date());

  const fetchFeedbacks = async () => {
    if (!API_URL) return;

    try {
      setLoading(true);
      const response = await fetch(API_URL);
      const data = await response.json();
      // Assume-se que o JSON venha como um array de objetos
      if (Array.isArray(data)) {
        setFeedbacks(data.reverse()); // Mais recentes primeiro
        setLastUpdate(new Date());
      }
    } catch (error) {
      console.error("Erro ao buscar feedbacks:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchFeedbacks();
    // Atualiza a cada 5 minutos (300000ms)
    const interval = setInterval(fetchFeedbacks, 300000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="w-full">
      {/* Header do Feed */}
      <div className="flex items-center justify-between mb-8 px-2">
        <div className="flex items-center gap-3">
          <div className="relative flex h-3 w-3">
            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-purple-400 opacity-75"></span>
            <span className="relative inline-flex rounded-full h-3 w-3 bg-purple-500"></span>
          </div>
          <span className="text-[10px] font-black uppercase tracking-[0.3em] text-purple-400">
            Feedbacks em Tempo Real
          </span>
        </div>
        <span className="text-[10px] font-bold text-zinc-600 uppercase tracking-widest">
          Última atualização: {lastUpdate.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
        </span>
      </div>

      {/* Grid de Feedbacks */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        <AnimatePresence mode="popLayout">
          {feedbacks.map((item, idx) => (
            <motion.div
              key={item.name + idx}
              layout
              initial={{ opacity: 0, scale: 0.9, y: 20 }}
              animate={{ opacity: 1, scale: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.8, transition: { duration: 0.2 } }}
              className="group relative p-6 rounded-[2rem] bg-zinc-900/40 border border-white/5 backdrop-blur-sm hover:border-purple-500/30 transition-all duration-500"
            >
              <div className="absolute top-6 right-6 opacity-10 group-hover:opacity-30 transition-opacity">
                <MessageSquare className="w-8 h-8 text-purple-500" />
              </div>

              <div className="flex gap-1 mb-4">
                {[...Array(5)].map((_, i) => (
                  <Star key={i} className="w-3 h-3 fill-purple-500 text-purple-500" />
                ))}
              </div>

              <p className="text-zinc-300 text-sm leading-relaxed mb-6 italic min-h-[60px]">
                "{item.text}"
              </p>

              <div className="flex items-center gap-3 border-t border-white/5 pt-4">
                <div className="w-10 h-10 rounded-full bg-gradient-to-br from-purple-600 to-indigo-700 flex items-center justify-center font-black text-xs text-white shadow-lg">
                  {item.name.charAt(0)}
                </div>
                <div>
                  <h4 className="text-white font-bold text-sm tracking-tight">{item.name}</h4>
                  <span className="text-[10px] font-black text-purple-500 uppercase tracking-[0.15em]">{item.tag}</span>
                </div>
              </div>
            </motion.div>
          ))}
        </AnimatePresence>
      </div>

      {/* Botão de Feedback do Google Form */}
      <div className="mt-12 flex justify-center">
        <a 
          href="SUA_URL_DO_GOOGLE_FORM_AQUI" 
          target="_blank" 
          className="text-[10px] font-black uppercase tracking-widest text-zinc-500 hover:text-purple-400 transition-colors flex items-center gap-2"
        >
          <span className="w-1 h-1 bg-zinc-800 rounded-full" />
          Enviar meu feedback
          <span className="w-1 h-1 bg-zinc-800 rounded-full" />
        </a>
      </div>
    </div>
  );
};

